VALUES
  ('judicial-d35ec6db-moex-00167', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於因公務員之作為所生之國家賠償責任，下列敘述何者正確？', '["適用國家賠償法之公務員，僅限於依公務人員任用法所任命之公務員", "受委託行使公權力之個人於其執行職務行使公權力時，視同委託機關之公務員", "行使公權力之行為，僅限於運用命令及強制手段干預人民自由及權利之行為", "由於我國採取國家自己責任，故公務人員是否有故意或過失在所不問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00168', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-113-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '管理機關於開放水域，已就使用該自然公物或人工設施為適當之警告或標示，人民仍從事具危險性活動者， 依國家賠償法規定，下列敘述何者正確？', '["使用人工設施所生之損害，國家不負損害賠償責任", "使用自然公物所生之損害，國家不負損害賠償責任", "無論係使用自然公物或人工設施所生之損害，國家皆應負損害賠償責任", "國家可主張減輕或免除損害賠償責任者，僅限於開放山域，不包括開放水域"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "204", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00169', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'essay', '甫上小學的 A，過年期間隨父母回臺南祖父母家過年，除了祖父母外，
眾多親戚長輩都慷慨給予紅包。過年期間親友往來頻繁，就讀大學的 B
隨父母到 A祖父母家拜年，大人閒聊時，B覺無趣，遂想去陪 A遊玩。
見 A正拿出壓歲錢一張一張數著玩，B心生一計，掏出為了去日本旅遊
而換的日幣萬元紙鈔，對 A 說：「這麼多張紙鈔很厚，帶起來好麻煩，
不如拿 10張千元鈔，跟我換這張萬元鈔，這樣就不用帶這麼厚了。」A
不懂分辨不同國家幣值，亦不知新臺幣並無萬元鈔，見紙鈔上的 10000
字樣，算了算數，的確是 10 個 1,000，便同意拿 10 張千元鈔與 B 的日
幣萬元鈔交換。請問 B的行為該如何評價？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00170', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'essay', 'A 到 B 家向 B 追討之前借給 B 的錢，沒想到 B 不但不還，還嘲諷 A 是
守財奴，才這麼點錢還急著追討。A盛怒之下，隨手拿起手邊的馬克杯，
邊叫囂要 B閉嘴，邊拿馬克杯猛力朝 B 太陽穴部位敲擊數次，B 頭部頓
時血流如注，失去意識倒地不起。A見狀連忙逃跑，待心緒稍定後打給
自己的女友 C，告知全情，C勸 A 應該立刻叫救護車救 B，A因害怕便
叫 C打電話叫救護車至 B家救 B。孰知，B因家人返家，在 C叫的救護
車抵達之前，就已經送醫診治獲救。請問 A的行為該如何評價？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00171', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於擄人勒贖罪，下列敘述何者錯誤？', '["意圖勒贖而擄人者屬之", "擄人後意圖勒贖者屬之", "如故意使人受重傷者，得處死刑", "如致人受重傷者得處死刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00172', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '處罰之裁判確定後，未執行或執行未完畢，而法律有變更，不處罰其行為者，依刑法之規定，其 效果為何？', '["其刑之宣告以已廢止論", "其刑之宣告以已執行論", "另由法務部長以行政處分赦免之", "免其刑之執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00173', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲依刑事訴訟法第 88 條第 1 項規定逮捕現行犯乙，將其監禁數日後始送交警察。下列敘述何者 正確？', '["甲之行為屬業務上正當行為，可阻卻違法", "甲之行為屬依法令之行為，可阻卻違法", "甲之行為屬正當防衛，可阻卻違法", "甲之行為不可阻卻違法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00174', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '下列何者並非構成要件錯誤？', '["打擊錯誤", "客體錯誤", "因果流程錯誤", "容許錯誤"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00175', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法預備犯及未遂犯之規定，下列敘述何者正確？', '["預備犯為結果發生前的前置處罰規定，因此亦屬刑法第25條未遂犯的一種類型", "行為之處罰以未遂為原則，既遂則按未遂之刑加重其刑二分之一", "行為之處罰以未遂為原則，法無明文亦可處罰未遂犯行", "實質預備犯係將預備行為直接入罪化而創設的獨立處罰規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00176', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於教唆犯，依實務見解，下列敘述何者錯誤？', '["甲教唆乙自殺，乙果真自殺身亡，甲不成立殺人罪之教唆犯", "甲教唆乙湮滅甲自己的犯罪證據，甲不成立湮滅證據罪之教唆犯", "甲犯案後教唆乙頂替自己，甲不成立頂替罪之教唆犯", "被告甲教唆乙偽證，為自己有利之供述，甲不成立偽證罪之教唆犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
